"""Auth endpoints: login, logout, me, change own password."""
from __future__ import annotations

from apiflask import APIBlueprint

from app.interface.deps import auth, auth_service, current_user, get_db
from app.interface.schemas import (
    ChangePasswordIn,
    LoginIn,
    MessageOut,
    TokenOut,
    UserOut,
)
from app.infrastructure.security.jwt import create_access_token

auth_bp = APIBlueprint("auth", __name__, url_prefix="/auth", tag="Auth")


@auth_bp.post("/login")
@auth_bp.input(LoginIn)
@auth_bp.output(TokenOut)
@auth_bp.doc(summary="Log in", description="Exchange username/password for a JWT access token.")
def login(json_data: dict):
    user = auth_service().authenticate(json_data["username"], json_data["password"])
    get_db().commit()  # persist any transparent password rehash
    token = create_access_token(user.id, user.role)
    return {"access_token": token, "token_type": "bearer"}


@auth_bp.post("/logout")
@auth_bp.output(MessageOut)
@auth_bp.auth_required(auth)
@auth_bp.doc(
    summary="Log out",
    description="Stateless JWT: the server has no session to destroy. The client "
    "discards the token. Returned for symmetry / audit logging.",
)
def logout():
    return {"message": "Logged out. Discard your access token."}


@auth_bp.get("/me")
@auth_bp.output(UserOut)
@auth_bp.auth_required(auth)
@auth_bp.doc(summary="Current user", description="Profile of the authenticated user.")
def me():
    return current_user()


@auth_bp.post("/change-password")
@auth_bp.input(ChangePasswordIn)
@auth_bp.output(MessageOut)
@auth_bp.auth_required(auth)
@auth_bp.doc(summary="Change own password")
def change_password(json_data: dict):
    user = current_user()
    auth_service().change_own_password(
        user.id, json_data["current_password"], json_data["new_password"]
    )
    get_db().commit()
    return {"message": "Password changed successfully."}

"""Chat endpoints: session CRUD, history load, and sending a message.

Every route is gated by a coarse RBAC permission (all roles may chat); the
service enforces per-user ownership and returns 404 for foreign sessions.

Two ways to send a message: a plain JSON request that returns both turns at once,
and an SSE endpoint that streams the assistant reply token-by-token (PLAN §3.5).
The streaming view validates and persists the user turn *before* opening the
response, so 404/422 still arrive as real HTTP status codes; only the assistant
tokens flow inside the event stream.
"""
from __future__ import annotations

import json
import uuid

from apiflask import APIBlueprint
from flask import Response, stream_with_context

from app.domain.user import Permission
from app.interface.deps import auth, chat_service, current_user, get_db
from app.interface.permissions import require_permission
from app.interface.schemas import (
    ChatMessageOut,
    ChatSessionDetailOut,
    ChatSessionOut,
    CreateSessionIn,
    MessageOut,
    SendMessageIn,
    SendMessageOut,
)

chat_bp = APIBlueprint("chat", __name__, url_prefix="/chat", tag="Chat")

_message_schema = ChatMessageOut()


def _sse(event: str, data: dict) -> str:
    """One SSE frame: a named event plus a JSON payload (PLAN §3.5)."""
    return f"event: {event}\ndata: {json.dumps(data)}\n\n"


@chat_bp.post("/sessions")
@chat_bp.auth_required(auth)
@chat_bp.input(CreateSessionIn)
@chat_bp.output(ChatSessionOut, status_code=201)
@chat_bp.doc(summary="Create a chat session")
@require_permission(Permission.USE_CHAT)
def create_session(json_data: dict):
    session = chat_service().create_session(current_user(), json_data.get("title"))
    get_db().commit()
    return session


@chat_bp.get("/sessions")
@chat_bp.auth_required(auth)
@chat_bp.output(ChatSessionOut(many=True))
@chat_bp.doc(summary="List own sessions", description="Most-recently-active first.")
@require_permission(Permission.MANAGE_OWN_CHATS)
def list_sessions():
    return chat_service().list_sessions(current_user())


@chat_bp.get("/sessions/<uuid:session_id>")
@chat_bp.auth_required(auth)
@chat_bp.output(ChatSessionDetailOut)
@chat_bp.doc(
    summary="Load a session with history",
    description="Returns the session and its messages in chronological order. "
    "404 if the session does not exist or belongs to another user.",
)
@require_permission(Permission.MANAGE_OWN_CHATS)
def get_session(session_id: uuid.UUID):
    return chat_service().get_session(current_user(), session_id)


@chat_bp.delete("/sessions/<uuid:session_id>")
@chat_bp.auth_required(auth)
@chat_bp.output(MessageOut)
@chat_bp.doc(summary="Delete own session", description="Cascades to its messages.")
@require_permission(Permission.MANAGE_OWN_CHATS)
def delete_session(session_id: uuid.UUID):
    chat_service().delete_session(current_user(), session_id)
    get_db().commit()
    return {"message": "Session deleted."}


@chat_bp.post("/sessions/<uuid:session_id>/messages")
@chat_bp.auth_required(auth)
@chat_bp.input(SendMessageIn)
@chat_bp.output(SendMessageOut, status_code=201)
@chat_bp.doc(
    summary="Send a message",
    description="Persists the user message, gets the assistant reply (mock LLM in "
    "this phase), persists it, and returns both. Streaming arrives in Day 5.",
)
@require_permission(Permission.USE_CHAT)
def send_message(session_id: uuid.UUID, json_data: dict):
    result = chat_service().send_message(current_user(), session_id, json_data["content"])
    get_db().commit()
    return result


@chat_bp.post("/sessions/<uuid:session_id>/messages/stream")
@chat_bp.auth_required(auth)
@chat_bp.input(SendMessageIn)
@chat_bp.doc(
    summary="Send a message (SSE streaming)",
    description=(
        "Persists the user turn, then streams the assistant reply as "
        "`text/event-stream`. Events: `meta` (the persisted user message + "
        "session title), repeated `token` (content deltas), and a terminal "
        "`done` (the persisted assistant message) or `error` (the partial reply "
        "that was still saved). Ownership/validation failures return 404/422 "
        "before the stream opens. Send the JWT as a Bearer header."
    ),
    responses={200: "Server-sent event stream of the assistant reply."},
)
@require_permission(Permission.USE_CHAT)
def stream_message(session_id: uuid.UUID, json_data: dict):
    svc = chat_service()
    db = get_db()
    # Validate + persist the user turn up front so 404/422 are real HTTP codes
    # and the user message is durable before the stream begins.
    handle = svc.open_stream(current_user(), session_id, json_data["content"])
    db.commit()

    def generate():
        yield _sse(
            "meta",
            {
                "session_id": str(handle.session.id),
                "title": handle.session.title,
                "user_message": _message_schema.dump(handle.user_message),
            },
        )
        for event in svc.stream_reply(handle, db.commit):
            if event["type"] == "token":
                yield _sse("token", {"value": event["value"]})
            elif event["type"] == "done":
                yield _sse(
                    "done",
                    {"assistant_message": _message_schema.dump(event["assistant_message"])},
                )
            elif event["type"] == "error":
                yield _sse(
                    "error",
                    {
                        "message": event["message"],
                        "assistant_message": _message_schema.dump(
                            event["assistant_message"]
                        ),
                    },
                )

    return Response(
        stream_with_context(generate()),
        mimetype="text/event-stream",
        headers={
            "Cache-Control": "no-cache",
            # Defeat proxy/worker response buffering so tokens flush immediately.
            "X-Accel-Buffering": "no",
        },
    )

"""Admin / Super Admin endpoints (PLAN §1.2 matrix).

Each route carries a coarse `@require_permission` gate; the service performs the
fine-grained, target-role-dependent checks (e.g. only super_admin may toggle an
admin) and cross-role constraints.
"""
from __future__ import annotations

import uuid

from apiflask import APIBlueprint

from app.domain.user import Permission
from app.interface.deps import auth, current_user, get_db, user_admin_service
from app.interface.permissions import require_permission
from app.interface.schemas import CreateUserIn, SetActiveIn, UserOut

admin_bp = APIBlueprint("admin", __name__, url_prefix="/admin", tag="Admin")


@admin_bp.get("/users")
@admin_bp.auth_required(auth)
@admin_bp.output(UserOut(many=True))
@admin_bp.doc(summary="List all users")
@require_permission(Permission.LIST_USERS)
def list_users():
    return user_admin_service().list_users(current_user())


@admin_bp.post("/users")
@admin_bp.auth_required(auth)
@admin_bp.input(CreateUserIn)
@admin_bp.output(UserOut, status_code=201)
@admin_bp.doc(
    summary="Create a user",
    description="admin may create role=user; super_admin may also create role=admin. "
    "super_admin cannot be created via the API.",
)
@require_permission(Permission.CREATE_USER)
def create_user(json_data: dict):
    user = user_admin_service().create_user(
        current_user(),
        username=json_data["username"],
        password=json_data["password"],
        role=json_data["role"],
    )
    get_db().commit()
    return user


@admin_bp.patch("/users/<uuid:user_id>/active")
@admin_bp.auth_required(auth)
@admin_bp.input(SetActiveIn)
@admin_bp.output(UserOut)
@admin_bp.doc(
    summary="Activate / deactivate a user",
    description="admin may toggle role=user; super_admin may also toggle role=admin. "
    "super_admin accounts cannot be modified.",
)
@require_permission(Permission.TOGGLE_USER_ACTIVE)
def set_active(user_id: uuid.UUID, json_data: dict):
    user = user_admin_service().set_active(current_user(), user_id, json_data["is_active"])
    get_db().commit()
    return user


@admin_bp.post("/users/<uuid:user_id>/promote")
@admin_bp.auth_required(auth)
@admin_bp.output(UserOut)
@admin_bp.doc(summary="Promote a user to admin", description="super_admin only.")
@require_permission(Permission.PROMOTE_USER_TO_ADMIN)
def promote(user_id: uuid.UUID):
    user = user_admin_service().promote_to_admin(current_user(), user_id)
    get_db().commit()
    return user

"""Dependency wiring for the interface layer.

Provides a request-scoped DB session, the Bearer-token authenticator (decodes
JWT -> loads the active user), and small factories that assemble services with
the request's repositories. Views stay thin; swapping a fake repo/LLM in tests
is just a different factory.
"""
from __future__ import annotations

from apiflask import HTTPTokenAuth
from flask import Flask, g
from sqlalchemy.orm import Session

from app.application.auth_service import AuthService
from app.application.chat_service import ChatService
from app.application.user_admin_service import UserAdminService
from app.infrastructure.config import get_settings
from app.infrastructure.db.models import User
from app.infrastructure.db.repositories import SqlChatRepository, SqlUserRepository
from app.infrastructure.db.session import SessionLocal
from app.infrastructure.llm import get_llm_provider
from app.infrastructure.security.jwt import TokenError, decode_access_token

auth = HTTPTokenAuth(scheme="Bearer", description="JWT access token from /auth/login")


def get_db() -> Session:
    if "db" not in g:
        g.db = SessionLocal()
    return g.db


def user_repository() -> SqlUserRepository:
    return SqlUserRepository(get_db())


def auth_service() -> AuthService:
    return AuthService(user_repository())


def user_admin_service() -> UserAdminService:
    return UserAdminService(user_repository())


def chat_repository() -> SqlChatRepository:
    return SqlChatRepository(get_db())


def chat_service() -> ChatService:
    return ChatService(chat_repository(), get_llm_provider(get_settings()))


@auth.verify_token
def verify_token(token: str) -> User | None:
    """Decode the JWT and load the active user, or None to reject (401)."""
    try:
        claims = decode_access_token(token)
    except TokenError:
        return None
    user = user_repository().get_by_id(claims.user_id)
    if user is None or not user.is_active:
        return None
    return user


def current_user() -> User:
    """The authenticated user for the current request."""
    return auth.current_user


def init_app(app: Flask) -> None:
    @app.teardown_appcontext
    def _close_db(_exc: BaseException | None) -> None:
        db = g.pop("db", None)
        if db is not None:
            db.close()

"""SQLAlchemy implementations of domain repository ports."""
from __future__ import annotations

import uuid

from sqlalchemy import func, select
from sqlalchemy.orm import Session

from app.domain.user import Role
from app.infrastructure.db.models import ChatSession, Message, User


class SqlUserRepository:
    """Implements `app.domain.ports.UserRepository`."""

    def __init__(self, session: Session) -> None:
        self._session = session

    def get_by_id(self, user_id: uuid.UUID) -> User | None:
        return self._session.get(User, user_id)

    def get_by_username(self, username: str) -> User | None:
        stmt = select(User).where(func.lower(User.username) == username.lower())
        return self._session.scalar(stmt)

    def add(self, user: User) -> User:
        self._session.add(user)
        self._session.flush()  # assign PK without committing (caller owns the tx)
        return user

    def list_all(self) -> list[User]:
        stmt = select(User).order_by(User.created_at.asc())
        return list(self._session.scalars(stmt).all())

    def count_active_by_role(self, role: Role) -> int:
        stmt = (
            select(func.count())
            .select_from(User)
            .where(User.role == role, User.is_active.is_(True))
        )
        return int(self._session.scalar(stmt) or 0)


class SqlChatRepository:
    """Implements `app.domain.ports.ChatRepository`."""

    def __init__(self, session: Session) -> None:
        self._session = session

    def add_session(self, session: ChatSession) -> ChatSession:
        self._session.add(session)
        self._session.flush()  # assign PK without committing (caller owns the tx)
        return session

    def get_session(self, session_id: uuid.UUID) -> ChatSession | None:
        return self._session.get(ChatSession, session_id)

    def list_sessions(self, user_id: uuid.UUID) -> list[ChatSession]:
        # Left-side list: most-recent first. No messages loaded -> avoids N+1.
        stmt = (
            select(ChatSession)
            .where(ChatSession.user_id == user_id)
            .order_by(ChatSession.updated_at.desc())
        )
        return list(self._session.scalars(stmt).all())

    def delete_session(self, session: ChatSession) -> None:
        # Messages cascade via the FK / relationship cascade.
        self._session.delete(session)
        self._session.flush()

    def add_message(self, message: Message) -> Message:
        self._session.add(message)
        self._session.flush()
        return message

    def list_messages(self, session_id: uuid.UUID) -> list[Message]:
        # Chronological history, served by ix_messages_session_created.
        stmt = (
            select(Message)
            .where(Message.session_id == session_id)
            .order_by(Message.created_at.asc())
        )
        return list(self._session.scalars(stmt).all())

"""Shared test fixtures.

`db_session` gives a real SQLAlchemy session on in-memory SQLite (fast, no
external service) for integration-style tests of repositories and seed.
`FakeUserRepository` is an in-memory port double for pure unit tests of services.
"""
from __future__ import annotations

import datetime as dt
import uuid
from collections.abc import Iterator, Sequence

import pytest
from sqlalchemy import create_engine
from sqlalchemy.orm import Session, sessionmaker
from sqlalchemy.pool import StaticPool

from app.domain.chat import LLMMessage
from app.domain.user import Role
from app.infrastructure.db.base import Base

# Importing the models module registers User, ChatSession and Message on the
# shared metadata so `create_all` builds every table.
from app.infrastructure.db.models import ChatSession, Message, User  # noqa: F401


@pytest.fixture
def db_session() -> Iterator[Session]:
    engine = create_engine(
        "sqlite://",
        connect_args={"check_same_thread": False},
        poolclass=StaticPool,
    )
    Base.metadata.create_all(engine)
    TestSession = sessionmaker(bind=engine, expire_on_commit=False, future=True)
    session = TestSession()
    try:
        yield session
    finally:
        session.close()
        Base.metadata.drop_all(engine)


class FakeUserRepository:
    """In-memory implementation of app.domain.ports.UserRepository."""

    def __init__(self) -> None:
        self._by_id: dict[uuid.UUID, User] = {}

    def get_by_id(self, user_id: uuid.UUID) -> User | None:
        return self._by_id.get(user_id)

    def get_by_username(self, username: str) -> User | None:
        for u in self._by_id.values():
            if u.username.lower() == username.lower():
                return u
        return None

    def add(self, user: User) -> User:
        if user.id is None:
            user.id = uuid.uuid4()
        self._by_id[user.id] = user
        return user

    def list_all(self) -> list[User]:
        return list(self._by_id.values())

    def count_active_by_role(self, role: Role) -> int:
        return sum(1 for u in self._by_id.values() if u.role == role and u.is_active)


@pytest.fixture
def fake_users() -> FakeUserRepository:
    return FakeUserRepository()


class FakeChatRepository:
    """In-memory implementation of app.domain.ports.ChatRepository.

    Mimics the DB defaults the ORM/server would supply (PK, timestamps) so
    service logic can be tested without a database.
    """

    def __init__(self) -> None:
        self._sessions: dict[uuid.UUID, ChatSession] = {}
        self._messages: dict[uuid.UUID, Message] = {}

    def add_session(self, session: ChatSession) -> ChatSession:
        if session.id is None:
            session.id = uuid.uuid4()
        now = dt.datetime.now(dt.timezone.utc)
        if session.created_at is None:
            session.created_at = now
        if session.updated_at is None:
            session.updated_at = now
        self._sessions[session.id] = session
        return session

    def get_session(self, session_id: uuid.UUID) -> ChatSession | None:
        return self._sessions.get(session_id)

    def list_sessions(self, user_id: uuid.UUID) -> list[ChatSession]:
        sessions = [s for s in self._sessions.values() if s.user_id == user_id]
        return sorted(sessions, key=lambda s: s.updated_at, reverse=True)

    def delete_session(self, session: ChatSession) -> None:
        self._sessions.pop(session.id, None)
        for mid in [m.id for m in self._messages.values() if m.session_id == session.id]:
            self._messages.pop(mid, None)

    def add_message(self, message: Message) -> Message:
        if message.id is None:
            message.id = uuid.uuid4()
        if message.created_at is None:
            message.created_at = dt.datetime.now(dt.timezone.utc)
        self._messages[message.id] = message
        return message

    def list_messages(self, session_id: uuid.UUID) -> list[Message]:
        msgs = [m for m in self._messages.values() if m.session_id == session_id]
        return sorted(msgs, key=lambda m: m.created_at)


class FakeLLMProvider:
    """Deterministic in-memory LLMProvider double; records the last prompt.

    `stream` yields the reply one character at a time so tests can assert the
    delta sequence. Set `fail_after` to raise mid-stream after that many deltas,
    simulating a dropped upstream so the partial-persist path is exercised.
    """

    def __init__(self, reply: str = "fake reply") -> None:
        self.reply = reply
        self.last_prompt: Sequence[LLMMessage] = ()
        self.fail_after: int | None = None

    def complete(self, messages: Sequence[LLMMessage]) -> str:
        self.last_prompt = list(messages)
        return self.reply

    def stream(self, messages: Sequence[LLMMessage]) -> Iterator[str]:
        self.last_prompt = list(messages)
        for i, ch in enumerate(self.reply):
            if self.fail_after is not None and i >= self.fail_after:
                raise RuntimeError("simulated upstream failure")
            yield ch


@pytest.fixture
def fake_chats() -> FakeChatRepository:
    return FakeChatRepository()


@pytest.fixture
def fake_llm() -> FakeLLMProvider:
    return FakeLLMProvider()

