# Serves the built SPA and reverse-proxies API calls to the backend, so the
# browser stays same-origin in production (no CORS needed). PLAN Day 6.
server {
    listen 80;
    server_name _;
    root /usr/share/nginx/html;
    index index.html;

    # SPA history fallback: unknown routes resolve to index.html.
    location / {
        try_files $uri $uri/ /index.html;
    }

    # Forward API prefixes to the backend service ("api" on the compose network).
    location ~ ^/(auth|chat|admin|health) {
        proxy_pass http://api:8000;
        proxy_http_version 1.1;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;

        # SSE streaming: disable buffering so assistant tokens flush immediately.
        proxy_buffering off;
        proxy_cache off;
        proxy_read_timeout 3600s;
    }
}

