// Thin fetch wrapper: prepends the API base, attaches the JWT bearer token,
// parses JSON, and normalises backend errors ({ "message": ... }) into ApiError.
// A 401 clears the stored token and notifies a registered handler so the router
// can bounce the user to /login.

const API_BASE = import.meta.env.VITE_API_BASE ?? ''
const TOKEN_KEY = 'llm_chat_token'

export class ApiError extends Error {
  status: number
  constructor(status: number, message: string) {
    super(message)
    this.status = status
    this.name = 'ApiError'
  }
}

export function getToken(): string | null {
  return localStorage.getItem(TOKEN_KEY)
}
export function setToken(token: string): void {
  localStorage.setItem(TOKEN_KEY, token)
}
export function clearToken(): void {
  localStorage.removeItem(TOKEN_KEY)
}

let unauthorizedHandler: (() => void) | null = null
export function onUnauthorized(handler: () => void): void {
  unauthorizedHandler = handler
}

export function authHeaders(): Record<string, string> {
  const token = getToken()
  return token ? { Authorization: `Bearer ${token}` } : {}
}

/** Read a backend error body ({ message } or marshmallow validation) into text. */
async function extractError(resp: Response): Promise<string> {
  try {
    const data = await resp.json()
    if (typeof data?.message === 'string') return data.message
    if (data?.detail) return JSON.stringify(data.detail)
    return JSON.stringify(data)
  } catch {
    return resp.statusText || `Request failed (${resp.status})`
  }
}

function handleUnauthorized(): void {
  clearToken()
  unauthorizedHandler?.()
}

export interface RequestOptions {
  method?: string
  body?: unknown
  auth?: boolean
}

export async function request<T>(path: string, opts: RequestOptions = {}): Promise<T> {
  const { method = 'GET', body, auth = true } = opts
  const headers: Record<string, string> = {}
  if (body !== undefined) headers['Content-Type'] = 'application/json'
  if (auth) Object.assign(headers, authHeaders())

  const resp = await fetch(`${API_BASE}${path}`, {
    method,
    headers,
    body: body !== undefined ? JSON.stringify(body) : undefined,
  })

  if (resp.status === 401) {
    handleUnauthorized()
    throw new ApiError(401, await extractError(resp))
  }
  if (!resp.ok) {
    throw new ApiError(resp.status, await extractError(resp))
  }
  // 204 / empty body tolerance.
  if (resp.status === 204) return undefined as T
  return (await resp.json()) as T
}

export { API_BASE }

