import { API_BASE, ApiError, authHeaders, clearToken, request } from './client'
import type {
  ChatSession,
  SendMessageResult,
  SessionDetail,
  StreamEvent,
} from './types'

export function listSessions() {
  return request<ChatSession[]>('/chat/sessions')
}

export function createSession(title?: string) {
  return request<ChatSession>('/chat/sessions', {
    method: 'POST',
    body: title ? { title } : {},
  })
}

export function getSession(id: string) {
  return request<SessionDetail>(`/chat/sessions/${id}`)
}

export function deleteSession(id: string) {
  return request<{ message: string }>(`/chat/sessions/${id}`, { method: 'DELETE' })
}

export function sendMessage(id: string, content: string) {
  return request<SendMessageResult>(`/chat/sessions/${id}/messages`, {
    method: 'POST',
    body: { content },
  })
}

/**
 * Stream the assistant reply over SSE.
 *
 * EventSource can't set an Authorization header, so we POST with fetch and parse
 * the `text/event-stream` body manually, yielding the backend's semantic events
 * (meta / token / done / error). Ownership/validation failures arrive as real
 * HTTP status codes before the stream opens — surfaced here as ApiError.
 */
export async function* streamMessage(
  id: string,
  content: string,
): AsyncGenerator<StreamEvent> {
  const resp = await fetch(`${API_BASE}/chat/sessions/${id}/messages/stream`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...authHeaders() },
    body: JSON.stringify({ content }),
  })

  if (!resp.ok || !resp.body) {
    if (resp.status === 401) clearToken()
    let message = resp.statusText
    try {
      message = (await resp.json())?.message ?? message
    } catch {
      /* keep statusText */
    }
    throw new ApiError(resp.status, message)
  }

  const reader = resp.body.getReader()
  const decoder = new TextDecoder()
  let buffer = ''

  while (true) {
    const { done, value } = await reader.read()
    if (done) break
    buffer += decoder.decode(value, { stream: true })

    // SSE frames are separated by a blank line.
    let sep: number
    while ((sep = buffer.indexOf('\n\n')) !== -1) {
      const frame = buffer.slice(0, sep)
      buffer = buffer.slice(sep + 2)
      const event = parseFrame(frame)
      if (event) yield event
    }
  }
}

function parseFrame(frame: string): StreamEvent | null {
  let eventName = 'message'
  const dataLines: string[] = []
  for (const line of frame.split('\n')) {
    if (line.startsWith('event:')) eventName = line.slice(6).trim()
    else if (line.startsWith('data:')) dataLines.push(line.slice(5).trim())
  }
  if (dataLines.length === 0) return null
  const payload = JSON.parse(dataLines.join('\n'))
  return { type: eventName, ...payload } as StreamEvent
}

