import { request } from './client'
import type { ExportPayload, Role, User } from './types'

export function listUsers() {
  return request<User[]>('/admin/users')
}

export function createUser(username: string, password: string, role: Role) {
  return request<User>('/admin/users', {
    method: 'POST',
    body: { username, password, role },
  })
}

export function setActive(userId: string, is_active: boolean) {
  return request<User>(`/admin/users/${userId}/active`, {
    method: 'PATCH',
    body: { is_active },
  })
}

export function promote(userId: string) {
  return request<User>(`/admin/users/${userId}/promote`, { method: 'POST' })
}

export function exportAll() {
  return request<ExportPayload>('/admin/export')
}

/** Trigger a browser download of the export JSON. */
export async function downloadExport(): Promise<void> {
  const data = await exportAll()
  const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' })
  const url = URL.createObjectURL(blob)
  const a = document.createElement('a')
  a.href = url
  const stamp = new Date().toISOString().slice(0, 19).replace(/[:T]/g, '-')
  a.download = `chat-export-${stamp}.json`
  a.click()
  URL.revokeObjectURL(url)
}

