import { defineStore } from 'pinia'
import * as chatApi from '@/api/chat'
import { ApiError } from '@/api/client'
import type { ChatMessage, ChatSession } from '@/api/types'

/** A message in the pane; may be mid-stream (`pending`) or carry an `error`. */
export interface UiMessage extends ChatMessage {
  pending?: boolean
  error?: string
}

interface ChatState {
  sessions: ChatSession[]
  activeId: string | null
  messages: UiMessage[]
  loadingSessions: boolean
  loadingHistory: boolean
  streaming: boolean
}

export const useChatStore = defineStore('chat', {
  state: (): ChatState => ({
    sessions: [],
    activeId: null,
    messages: [],
    loadingSessions: false,
    loadingHistory: false,
    streaming: false,
  }),
  actions: {
    async loadSessions() {
      this.loadingSessions = true
      try {
        this.sessions = await chatApi.listSessions()
      } finally {
        this.loadingSessions = false
      }
    },

    async openSession(id: string) {
      this.activeId = id
      this.loadingHistory = true
      try {
        const detail = await chatApi.getSession(id)
        this.messages = detail.messages
      } finally {
        this.loadingHistory = false
      }
    },

    /** Start a fresh, unsaved conversation — persisted on the first send. */
    newSession() {
      this.activeId = null
      this.messages = []
    },

    async remove(id: string) {
      await chatApi.deleteSession(id)
      this.sessions = this.sessions.filter((s) => s.id !== id)
      if (this.activeId === id) this.newSession()
    },

    async send(content: string) {
      if (this.streaming) return

      // Persist the session lazily so empty drafts never clutter the sidebar.
      if (!this.activeId) {
        const created = await chatApi.createSession()
        this.sessions.unshift(created)
        this.activeId = created.id
        this.messages = []
      }
      const sid = this.activeId!

      const userMsg: UiMessage = {
        id: `tmp-user-${Date.now()}`,
        role: 'user',
        content,
        created_at: new Date().toISOString(),
      }
      const asstMsg: UiMessage = {
        id: `tmp-asst-${Date.now()}`,
        role: 'assistant',
        content: '',
        created_at: new Date().toISOString(),
        pending: true,
      }
      this.messages.push(userMsg, asstMsg)
      this.streaming = true

      try {
        for await (const ev of chatApi.streamMessage(sid, content)) {
          if (ev.type === 'meta') {
            Object.assign(userMsg, ev.user_message)
            this.applyTitle(sid, ev.title)
          } else if (ev.type === 'token') {
            asstMsg.content += ev.value
          } else if (ev.type === 'done') {
            Object.assign(asstMsg, ev.assistant_message, { pending: false })
          } else if (ev.type === 'error') {
            Object.assign(asstMsg, ev.assistant_message, {
              pending: false,
              error: ev.message,
            })
          }
        }
      } catch (err) {
        asstMsg.pending = false
        asstMsg.error = err instanceof ApiError ? err.message : 'Streaming failed'
      } finally {
        asstMsg.pending = false
        this.streaming = false
        this.bumpSession(sid)
      }
    },

    /** Reflect the auto-generated title and move the session to the top. */
    applyTitle(sid: string, title: string | null) {
      const s = this.sessions.find((x) => x.id === sid)
      if (s && title && !s.title) s.title = title
    },

    bumpSession(sid: string) {
      const idx = this.sessions.findIndex((x) => x.id === sid)
      if (idx > 0) {
        const [s] = this.sessions.splice(idx, 1)
        s.updated_at = new Date().toISOString()
        this.sessions.unshift(s)
      }
    },
  },
})

