:root {
  --bg: #0f1117;
  --bg-elevated: #171a23;
  --bg-sidebar: #11131a;
  --bg-input: #1e222d;
  --border: #2a2f3a;
  --text: #e6e8ee;
  --text-dim: #9aa0ad;
  --accent: #6d8bff;
  --accent-hover: #5a79f0;
  --danger: #e5594e;
  --danger-dim: #7a2a26;
  --user-bubble: #243049;
  --ok: #4caf7d;
  --radius: 10px;
  --shadow: 0 2px 12px rgba(0, 0, 0, 0.35);
  color-scheme: dark;
}

* {
  box-sizing: border-box;
}

html,
body,
#app {
  height: 100%;
  margin: 0;
}

body {
  font-family: 'Segoe UI', system-ui, -apple-system, 'PingFang TC', 'Microsoft JhengHei',
    sans-serif;
  background: var(--bg);
  color: var(--text);
  font-size: 15px;
  line-height: 1.55;
}

button {
  font: inherit;
  cursor: pointer;
}

input,
textarea,
select {
  font: inherit;
  color: var(--text);
  background: var(--bg-input);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 0.55rem 0.7rem;
  outline: none;
}
input:focus,
textarea:focus,
select:focus {
  border-color: var(--accent);
}

a {
  color: var(--accent);
  text-decoration: none;
}

/* ---- shared button styles ---- */
.btn {
  border: 1px solid var(--border);
  background: var(--bg-input);
  color: var(--text);
  border-radius: 8px;
  padding: 0.5rem 0.9rem;
  transition: background 0.15s, border-color 0.15s, opacity 0.15s;
}
.btn:hover {
  border-color: var(--accent);
}
.btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}
.btn-primary {
  background: var(--accent);
  border-color: var(--accent);
  color: #fff;
}
.btn-primary:hover {
  background: var(--accent-hover);
  border-color: var(--accent-hover);
}
.btn-danger {
  border-color: var(--danger-dim);
  color: var(--danger);
}
.btn-danger:hover {
  background: var(--danger-dim);
  border-color: var(--danger);
  color: #fff;
}
.btn-sm {
  padding: 0.3rem 0.55rem;
  font-size: 0.85rem;
}

.error-text {
  color: var(--danger);
  font-size: 0.88rem;
}

.badge {
  display: inline-block;
  font-size: 0.72rem;
  padding: 0.1rem 0.5rem;
  border-radius: 999px;
  border: 1px solid var(--border);
  color: var(--text-dim);
  text-transform: uppercase;
  letter-spacing: 0.04em;
}
.badge-admin {
  color: var(--accent);
  border-color: var(--accent);
}
.badge-super {
  color: #ffb74d;
  border-color: #ffb74d;
}

/* thin scrollbars */
*::-webkit-scrollbar {
  width: 9px;
  height: 9px;
}
*::-webkit-scrollbar-thumb {
  background: var(--border);
  border-radius: 99px;
}

