"""Health check endpoints.

`/health` is a liveness probe (process up). `/health/ready` is a readiness
probe that verifies the DB connection — used by docker-compose healthcheck.
The LLM upstream check is wired in later (Bonus, PLAN Day 6).
"""
from __future__ import annotations

from apiflask import APIBlueprint
from sqlalchemy import text

from app.infrastructure.db.session import engine

health_bp = APIBlueprint("health", __name__, tag="Health")


@health_bp.get("/health")
@health_bp.doc(summary="Liveness probe", description="Returns ok if the process is up.")
def health():
    return {"status": "ok"}


@health_bp.get("/health/ready")
@health_bp.doc(summary="Readiness probe", description="Verifies DB connectivity.")
def readiness():
    checks: dict[str, str] = {}
    healthy = True

    try:
        with engine.connect() as conn:
            conn.execute(text("SELECT 1"))
        checks["database"] = "ok"
    except Exception as exc:  # noqa: BLE001 - report any failure as unhealthy
        checks["database"] = f"error: {exc.__class__.__name__}"
        healthy = False

    status_code = 200 if healthy else 503
    return {"status": "ok" if healthy else "degraded", "checks": checks}, status_code

"""LLM provider selection.

`get_llm_provider` returns the configured `LLMProvider` implementation: the
deterministic offline mock, or the real Groq adapter (PLAN §3.5). The Groq adapter
is imported lazily so a mock-only deployment never needs the `openai` dependency
loaded, and a missing API key fails fast rather than erroring mid-stream.
"""
from __future__ import annotations

from app.domain.ports import LLMProvider
from app.infrastructure.config import Settings
from app.infrastructure.llm.mock import MockLLMProvider


def get_llm_provider(settings: Settings) -> LLMProvider:
    provider = settings.llm_provider.lower()
    if provider == "mock":
        return MockLLMProvider()
    if provider == "groq":
        if not settings.groq_api_key:
            raise RuntimeError(
                "LLM_PROVIDER=groq requires GROQ_API_KEY to be set "
                "(use LLM_PROVIDER=mock for an offline demo)."
            )
        from app.infrastructure.llm.groq import GroqProvider

        return GroqProvider(
            api_key=settings.groq_api_key,
            base_url=settings.groq_base_url,
            model=settings.llm_model,
        )
    raise ValueError(
        f"Unknown LLM_PROVIDER={settings.llm_provider!r} (expected 'mock' or 'groq')"
    )

